Spacer(modifier = Modifier.height(16.dp))
// Campo de contraseña ChatBotEditText( value = userPassword, onValueChange = onPasswordChange, label = "Contraseña", leadingIcon = Res.drawable.baseline_lock_24, trailingIcon = Res.drawable.baseline_lock_24, isPassword = true, leadingIconStatus = true, trailingIconStatus = false, modifier = Modifier.fillMaxWidth() )
Spacer(modifier = Modifier.height(8.dp)) // MD3: small = 8dp (checkbox agrupa con contraseña)
// Checkbox "Recordar contraseña" Row( modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically ) { Checkbox( checked = rememberCredentials, onCheckedChange = onRememberCredentialsChange, colors = CheckboxDefaults.colors( checkedColor = MaterialTheme.colorScheme.primary ) ) Spacer(modifier = Modifier.width(4.dp)) Text( text = "Recordar contraseña", style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurface ) }
Spacer(modifier = Modifier.height(16.dp))
// Botón de login ChatBotButton( text = "Iniciar Sesión", onClick = { onLoginClick(userCode, userPassword) }, enabled = userCode.isNotBlank() && userPassword.isNotBlank(), leadingiconResourceId = Res.drawable.outline_login_24, modifier = Modifier.fillMaxWidth() )
Spacer(modifier = Modifier.height(16.dp))
// Botón de invitado TextButton(onClick = onGuestClick) { Text( text = "Continuar como invitado", color = MaterialTheme.colorScheme.primary ) } } }

